<?php
/*
Plugin Name: User Files Upload
Description: Allows users to upload profile pictures and documents to wp-content/uploads/user-files/.
Version: 1.0.0
Author: OpenAI
*/

if (!defined('ABSPATH')) {
    exit;
}

class UFU_User_Files_Upload {
    private static $instance = null;
    private $upload_subdir = 'user-files';

    public static function instance() {
        if (self::$instance === null) {
            self::$instance = new self();
        }
        return self::$instance;
    }

    private function __construct() {
        add_shortcode('user_files_upload', array($this, 'render_shortcode'));
        add_action('admin_post_ufu_upload_file', array($this, 'handle_upload'));
        add_action('admin_post_nopriv_ufu_upload_file', array($this, 'handle_upload'));
        add_action('wp_enqueue_scripts', array($this, 'enqueue_assets'));
    }

    public function enqueue_assets() {
        wp_register_style('ufu-user-files-upload', false);
        wp_enqueue_style('ufu-user-files-upload');
        $css = '
            .ufu-upload-form{max-width:640px;padding:20px;border:1px solid #ddd;border-radius:8px;background:#fff}
            .ufu-upload-form label{display:block;margin:0 0 8px;font-weight:600}
            .ufu-upload-form input[type="file"]{display:block;margin:0 0 16px}
            .ufu-upload-form button{padding:10px 16px;border:0;border-radius:4px;background:#2271b1;color:#fff;cursor:pointer}
            .ufu-upload-form .ufu-message{margin:0 0 16px;padding:10px 12px;border-radius:4px}
            .ufu-upload-form .ufu-success{background:#ecf7ed;color:#1e6b2d;border:1px solid #b7e1bf}
            .ufu-upload-form .ufu-error{background:#fdeeee;color:#8a1f11;border:1px solid #f1b7b7}
        ';
        wp_add_inline_style('ufu-user-files-upload', $css);
    }

    public function render_shortcode() {
        if (!is_user_logged_in()) {
            return '<p>You must be logged in to upload files.</p>';
        }

        $message = '';
        if (!empty($_GET['ufu_status'])) {
            $status = sanitize_text_field(wp_unslash($_GET['ufu_status']));
            if ($status === 'success') {
                $message = '<div class="ufu-message ufu-success">File uploaded successfully.</div>';
            } elseif ($status === 'error') {
                $message = '<div class="ufu-message ufu-error">There was an error uploading your file.</div>';
            }
        }

        $action_url = esc_url(admin_url('admin-post.php'));
        $nonce = wp_create_nonce('ufu_upload_file');

        ob_start();
        echo '<form class="ufu-upload-form" method="post" action="' . $action_url . '" enctype="multipart/form-data">';
        echo $message;
        echo '<input type="hidden" name="action" value="ufu_upload_file">';
        echo '<input type="hidden" name="_wpnonce" value="' . esc_attr($nonce) . '">';
        echo '<label for="ufu_file">Upload Profile Picture or Document</label>';
        echo '<input type="file" id="ufu_file" name="ufu_file" accept=".jpg,.jpeg,.png,.gif,.pdf,.doc,.docx,.txt,.rtf,.odt,image/*,application/pdf,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document">';
        echo '<button type="submit">Upload File</button>';
        echo '</form>';
        return ob_get_clean();
    }

    public function handle_upload() {
        if (!is_user_logged_in()) {
            wp_die('Unauthorized', 403);
        }

        if (!isset($_POST['_wpnonce']) || !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['_wpnonce'])), 'ufu_upload_file')) {
            wp_die('Invalid nonce', 403);
        }

        if (empty($_FILES['ufu_file']) || !isset($_FILES['ufu_file']['name'])) {
            $this->redirect_with_status('error');
        }

        $file = $_FILES['ufu_file'];

        if (!empty($file['error'])) {
            $this->redirect_with_status('error');
        }

        $allowed_mimes = array(
            'jpg|jpeg|jpe' => 'image/jpeg',
            'png'          => 'image/png',
            'gif'          => 'image/gif',
            'pdf'          => 'application/pdf',
            'doc'          => 'application/msword',
            'docx'         => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
            'txt'          => 'text/plain',
            'rtf'          => 'application/rtf',
            'odt'          => 'application/vnd.oasis.opendocument.text',
        );

        $overrides = array(
            'test_form' => false,
            'mimes'     => $allowed_mimes,
        );

        require_once ABSPATH . 'wp-admin/includes/file.php';
        require_once ABSPATH . 'wp-admin/includes/image.php';

        $upload_dir = wp_upload_dir();
        $target_dir = trailingslashit($upload_dir['basedir']) . $this->upload_subdir;

        if (!file_exists($target_dir)) {
            wp_mkdir_p($target_dir);
        }

        add_filter('upload_dir', array($this, 'filter_upload_dir'));
        $uploaded = wp_handle_upload($file, $overrides);
        remove_filter('upload_dir', array($this, 'filter_upload_dir'));

        if (isset($uploaded['error'])) {
            $this->redirect_with_status('error');
        }

        $user_id = get_current_user_id();
        $file_url = isset($uploaded['url']) ? esc_url_raw($uploaded['url']) : '';
        $file_path = isset($uploaded['file']) ? sanitize_text_field($uploaded['file']) : '';
        $file_type = isset($uploaded['type']) ? sanitize_text_field($uploaded['type']) : '';

        if ($file_url && $file_path) {
            $existing = get_user_meta($user_id, 'ufu_uploaded_files', true);
            if (!is_array($existing)) {
                $existing = array();
            }

            $existing[] = array(
                'url'  => $file_url,
                'path' => $file_path,
                'type' => $file_type,
                'time' => current_time('mysql'),
            );

            update_user_meta($user_id, 'ufu_uploaded_files', $existing);
        }

        $this->redirect_with_status('success');
    }

    public function filter_upload_dir($dirs) {
        $subdir = '/' . trim($this->upload_subdir, '/');
        $dirs['subdir'] = $subdir;
        $dirs['path'] = $dirs['basedir'] . $subdir;
        $dirs['url'] = $dirs['baseurl'] . $subdir;
        return $dirs;
    }

    private function redirect_with_status($status) {
        $ref = wp_get_referer();
        if (!$ref) {
            $ref = home_url('/');
        }
        $url = add_query_arg('ufu_status', $status, $ref);
        wp_safe_redirect($url);
        exit;
    }
}

UFU_User_Files_Upload::instance();